// Only act on completed checkouts. Pull the session id to re-verify with Stripe.
const body = $input.item.json.body || $input.item.json || {};
const type = body.type || '';
if (type !== 'checkout.session.completed') {
  return { json: { ignore: true, status: 200, note: 'ignored event ' + (type || 'unknown') } };
}
const obj = (body.data && body.data.object) || {};
const sid = String(obj.id || '').trim();
if (sid.indexOf('cs_') !== 0) return { json: { ignore: true, status: 200, note: 'no checkout session id' } };
return { json: { ignore: false, session_id: sid } };

// Re-verify with Stripe (don't trust the raw webhook body), then work out which
// product they bought. NO metadata required: we read the Stripe product name on
// the purchased line item and map it. Explicit metadata.product still wins if set.
const s = $input.item.json || {};
if (s.error) return { json: { ok: false, status: 400, error: 'Stripe: ' + (s.error.message || 'lookup failed') } };
if (!s.id) return { json: { ok: false, status: 404, error: 'Checkout session not found' } };
if (s.status !== 'complete') return { json: { ok: false, status: 402, error: 'Checkout not complete (status ' + s.status + ')' } };
const meta = s.metadata || {};
const email = (s.customer_details && s.customer_details.email) || s.customer_email || '';
// Map any human label (Stripe product name / description / metadata) to a key.
function mapName(str) {
  const t = String(str || '').toLowerCase();
  if (t.indexOf('sentinel') !== -1) return 'sentinel';
  if (t.indexOf('sales') !== -1 || t.indexOf('engine') !== -1 || t.indexOf('lead') !== -1) return 'sales_engine';
  if (t.indexOf('luxi') !== -1) return 'luxi';
  if (t.indexOf('smart quote') !== -1 || t.indexOf('smart_quote') !== -1 || t.indexOf('advisor') !== -1) return 'smart_quote';
  if (t.indexOf('ava') !== -1) return 'ava';
  if (t.indexOf('mga') !== -1) return 'mga';
  return '';
}
let product = String(meta.product || '').trim();
let plan = String(meta.selected_plan || meta.plan || '').trim();
let productLabel = '';
if (!product) {
  const li = (s.line_items && s.line_items.data) || [];
  const first = li[0] || {};
  const prod = (first.price && first.price.product) || {};
  productLabel = prod.name || first.description || '';
  product = mapName(productLabel) || mapName(first.description) || '';
}
if (!email) return { json: { ok: false, status: 400, error: 'No email on the session' } };
if (!product) return { json: { ok: false, status: 400, error: 'Could not determine product from purchase (line item: "' + productLabel + '"). Name the Stripe product clearly (e.g. include "Sentinel" or "Sales Engine") or add metadata product=...' } };
return { json: { ok: true, email: email, product: product, plan: plan } };

// Build the buyer welcome (with a set-password link via the normal forgot-password
// flow) and the internal notification. Provisioning never fails the buyer's experience.
let r = $input.item.json; if (Array.isArray(r)) r = r[0] || {};
const v = $('Verify + Map').item.json;
const email = v.email; const product = v.product; const plan = v.plan || '';
const created = r && r.account_created;
const prettyProduct = product.replace(/_/g, ' ').replace(/\b\w/g, c => c.toUpperCase());
const setPw = 'https://crystallux.org/forgot-password.html';
const login = 'https://crystallux.org/login.html';
const buyerHtml = '<p>Welcome to Crystallux \u2014 your <strong>' + prettyProduct + '</strong> account is ready.</p>' +
  '<p>Two quick steps to get in:</p>' +
  '<ol><li>Set your password: <a href="' + setPw + '">' + setPw + '</a> (enter this email, ' + email + ').</li>' +
  '<li>Log in: <a href="' + login + '">' + login + '</a> and you will land on your dashboard.</li></ol>' +
  '<p>A specialist will also reach out within 24 hours to tailor it to your business. Questions? Just reply.</p>';
const maryHtml = '<p>\uD83D\uDCB0 New PAID signup auto-provisioned.</p>' +
  '<ul><li>Email: <strong>' + email + '</strong></li><li>Product: ' + product + (plan ? ' (' + plan + ')' : '') + '</li>' +
  '<li>New account: ' + (created ? 'yes' : 'existing, product added') + '</li></ul>' +
  '<p>Set their industry + city to start lead-gen.</p>';
return { json: {
  notify_to_mary: { From: 'info@crystallux.org', To: 'info@crystallux.org', Subject: 'New paid signup: ' + email + ' (' + product + ')', HtmlBody: maryHtml, MessageStream: 'outbound' },
  welcome_to_buyer: { From: 'info@crystallux.org', To: email, Subject: 'Your Crystallux account is ready', HtmlBody: buyerHtml, MessageStream: 'outbound' },
  email: email, product: product, account_created: !!created
} };
